{
  "mode": "method",
  "tests": [
    {
      "name": "valid_pending_reviews_for_admin",
      "input": {
        "userId": "admin_user",
        "role": "admin"
      },
      "output": [
        {
          "reviewId": "1",
          "challengeId": "101",
          "status": "pending",
          "userRole": "admin"
        },
        {
          "reviewId": "2",
          "challengeId": "102",
          "status": "pending",
          "userRole": "admin"
        }
      ],
      "notes": "Tests if admin can fetch all pending reviews."
    },
    {
      "name": "valid_pending_reviews_for_participant",
      "input": {
        "userId": "participant_user",
        "role": "participant"
      },
      "output": [
        {
          "reviewId": "3",
          "challengeId": "103",
          "status": "pending",
          "userRole": "participant"
        }
      ],
      "notes": "Tests if participant can fetch their pending reviews."
    },
    {
      "name": "no_pending_reviews_for_nonexistent_user",
      "input": {
        "userId": "nonexistent_user",
        "role": "participant"
      },
      "output": [],
      "notes": "Tests behavior when a user with no reviews is queried."
    },
    {
      "name": "active_challenge_filtering",
      "input": {
        "userId": "reviewer_user",
        "role": "reviewer"
      },
      "output": [
        {
          "reviewId": "4",
          "challengeId": "104",
          "status": "pending",
          "userRole": "reviewer"
        }
      ],
      "notes": "Tests if only active challenges are returned."
    },
    {
      "name": "inactive_challenge_exclusion",
      "input": {
        "userId": "reviewer_user",
        "role": "reviewer"
      },
      "output": [],
      "notes": "Tests that inactive challenges are excluded from results."
    },
    {
      "name": "role_based_review_access",
      "input": {
        "userId": "role_based_user",
        "role": "observer"
      },
      "output": [],
      "notes": "Tests that users without review roles cannot access reviews."
    },
    {
      "name": "multiple_roles_for_single_challenge",
      "input": {
        "userId": "multi_role_user",
        "role": "participant"
      },
      "output": [
        {
          "reviewId": "5",
          "challengeId": "105",
          "status": "pending",
          "userRole": "participant"
        },
        {
          "reviewId": "6",
          "challengeId": "105",
          "status": "pending",
          "userRole": "reviewer"
        }
      ],
      "notes": "Tests if a user with multiple roles can access their reviews."
    },
    {
      "name": "format_validation",
      "input": {
        "userId": "format_user",
        "role": "admin"
      },
      "output": [
        {
          "reviewId": "7",
          "challengeId": "106",
          "status": "pending",
          "userRole": "admin"
        }
      ],
      "notes": "Tests if the response format is consistent and includes user role."
    }
  ],
  "assumptions": "User roles are correctly assigned in the database.",
  "notes": "Ensure all API endpoints are reachable and functioning."
}
